export function AdminLayout({ children }: AdminLayoutProps) {
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const navigate = useNavigate();
  const location = useLocation();

  const sidebarExpanded = !sidebarCollapsed;

  const navigationItems = [
    {
      label: "Admin Dashboard",
      path: "/",
      Icon: DashboardIcon,
    },
    {
      label: "Masters",
      path: "/admin/masters",
      Icon: MasterIcon,
    },
    {
      label: "Employee",
      path: "/admin/employee",
      Icon: EmployeeIcon,
    },
    {
      label: "Travel",
      path: "/travel-request",
      Icon: TravelIcon,
    },
    {
      label: "Expense",
      path: "/admin/expense",
      Icon: ExpenseIcon,
    },
    {
      label: "Leave",
      path: "/admin/leave",
      Icon: LeaveIcon,
    },
    {
      label: "Reports",
      path: "/admin/reports",
      Icon: ReportsIcon,
    },
    {
      label: "Settings",
      path: "/admin/settings",
      Icon: SettingsIcon,
    },
  ];

  return (
    <div className="min-h-screen bg-[#F5F9FF]">
      {/* Sidebar */}
      <aside
        className={cn(
          "fixed left-0 top-0 z-40 h-screen bg-white transition-all duration-700 ease-in-out overflow-hidden",
          sidebarExpanded ? "w-[330px]" : "w-20",
        )}
      >
        <div className="flex h-full flex-col">
          {/* Logo Section */}
          <div className="flex h-20 items-center px-6">
            <div className="flex items-center gap-3">
              <div className="h-10 w-10 rounded-lg bg-gradient-to-br from-blue-500 to-blue-600 flex items-center justify-center">
                <svg
                  width="24"
                  height="24"
                  viewBox="0 0 34 40"
                  fill="none"
                  className="text-white"
                >
                  <path d="M22.7453 0.657398C22.6688 1.03271 22.8427 1.4617 24.3419 2.27738C24.3917 2.30455 24.4424 2.33188 24.4936 2.35954L24.5855 3.44691L24.4741 3.37907C24.4285 3.35125 24.3684 3.36459 24.3397 3.40884L24.2783 3.50368C24.2496 3.54793 24.2634 3.60617 24.309 3.63399L24.6171 3.8214L24.7099 4.91918L24.6416 4.87753C24.5959 4.84971 24.5359 4.86305 24.5072 4.9073L24.4458 5.00214C24.4171 5.04639 24.4308 5.10463 24.4765 5.13245L24.7414 5.29383L24.8159 6.17443L25.4603 6.5665L25.9303 3.10885C26.7407 3.52109 27.5376 3.91234 28.0965 4.18369L28.1564 5.32783L28.5849 5.58861L28.8855 4.48758L29.2465 4.56697L29.0158 4.28618L29.908 3.54533L29.4794 3.28455L28.3908 3.72948C27.8958 3.35955 27.1859 2.8336 26.4509 2.30504L29.4586 0.392064L28.8143 0L27.9639 0.317718L27.699 0.156338C27.6533 0.12852 27.5933 0.141859 27.5646 0.186109L27.5032 0.280953C27.4745 0.325202 27.4882 0.383443 27.5339 0.411261L27.6022 0.452907L26.542 0.848875L26.234 0.661303C26.1883 0.633484 26.1282 0.646824 26.0996 0.691073L26.0381 0.785917C26.0095 0.830166 26.0232 0.888407 26.0689 0.916225L26.1801 0.983901L25.13 1.37613C25.0822 1.34343 25.0347 1.31122 24.9879 1.27933C23.5786 0.324714 23.1046 0.359365 22.7891 0.589397C22.7665 0.60599 22.7507 0.630393 22.7453 0.657398Z" fill="currentColor"/>
                </svg>
              </div>
              <div
                className={cn(
                  "transition-all duration-700 ease-in-out overflow-hidden",
                  sidebarExpanded ? "w-auto opacity-100" : "w-0 opacity-0"
                )}
              >
                <img
                  src="https://api.builder.io/api/v1/image/assets/TEMP/5223895ecc2e0f6856b26bb42baff71167a0d317?width=328"
                  alt="Travel Expenses Pro"
                  className="h-4 w-auto"
                />
              </div>
            </div>
          </div>

          {/* Navigation */}
          <nav className="flex-1 overflow-y-auto px-6 py-4">
            <div className="space-y-2">
              {navigationItems.map(({ label, path, Icon, children }) => {
                const hasChildren = Array.isArray(children) && children.length > 0;
                const isActive =
                  location.pathname === path ||
                  location.pathname.startsWith(path + "/") ||
                  (path === "/admin/masters" && location.pathname.startsWith("/admin/masters")) ||
                  (hasChildren && children!.some((c) => location.pathname === c.path || location.pathname.startsWith(c.path + "/")));

                return (
                  <div key={label}>
                    <NavItem
                      icon={<Icon />}
                      label={label}
                      active={isActive}
                      expanded={sidebarExpanded}
                      onClick={() => navigate(path)}
                    />
                    {hasChildren && sidebarExpanded && (
                      <div className="mt-1 pl-10 space-y-1">
                        {children!.map((c) => {
                          const childActive = location.pathname === c.path || location.pathname.startsWith(c.path + "/");
                          return (
                            <button
                              key={c.label}
                              onClick={() => navigate(c.path)}
                              className={cn(
                                "flex w-full items-center rounded-[8px] py-2 px-4 text-sm transition-colors",
                                childActive
                                  ? "bg-[#3B82F7] text-white"
                                  : "text-[#6B7280] hover:bg-[#3B82F7]/10 hover:text-[#1C1F37]"
                              )}
                            >
                              {c.label}
                            </button>
                          );
                        })}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </nav>
        </div>
      </aside>

      {/* Main Content */}
      <div
        className={cn(
          "transition-all duration-700 ease-in-out min-h-screen",
          sidebarExpanded ? "ml-[330px]" : "ml-20",
        )}
      >
        {/* Header */}
        <header className="sticky top-0 z-30 h-20 bg-white px-6">
          <div className="flex h-full items-center justify-between">
            <button
              aria-label="Toggle sidebar"
              onClick={() => setSidebarCollapsed(!sidebarCollapsed)}
              className="flex h-10 w-10 items-center justify-center rounded-lg hover:bg-gray-100 transition-colors"
            >
              <MenuIcon />
            </button>

            <div className="flex items-center gap-4">
              <button
                aria-label="Notifications"
                className="flex h-10 w-10 items-center justify-center rounded-lg bg-gray-50 hover:bg-gray-100 transition-colors"
              >
                <BellIcon />
              </button>
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <button className="flex items-center gap-3 rounded-md p-1.5 hover:bg-gray-100 transition-colors">
                    <img
                      src="https://api.builder.io/api/v1/image/assets/TEMP/f608110c5bb486e70228637345583ddd9f1e7591?width=80"
                      alt="John Admin"
                      className="h-10 w-10 rounded-md object-cover"
                    />
                    <span className="text-sm font-medium text-[#1C1F37]">
                      John Admin
                    </span>
                  </button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-56">
                  <DropdownMenuLabel>My Account</DropdownMenuLabel>
                  <DropdownMenuSeparator />
                  <DropdownMenuItem>Profile</DropdownMenuItem>
                  <DropdownMenuItem>Settings</DropdownMenuItem>
                  <DropdownMenuSeparator />
                  <DropdownMenuItem
                    onClick={() => {
                      clearAuth();
                      navigate("/login", { replace: true });
                    }}
                  >
                    Logout
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </div>
        </header>

        {/* Main Content Area */}
        <main className="p-6">
          {children}
        </main>
      </div>
    </div>
  );
}

interface NavItemProps {
  icon: React.ReactNode;
  label: string;
  active?: boolean;
  expanded: boolean;
  onClick?: () => void;
}

function NavItem({
  icon,
  label,
  active = false,
  expanded,
  onClick,
}: NavItemProps) {
  return (
    <button
      onClick={onClick}
      className={cn(
        "group flex w-full items-center rounded-[10px] py-3 px-5 transition-all duration-200 relative",
        active
          ? "bg-[#3B82F7] text-white shadow-sm"
          : "text-[#6B7280] hover:bg-[#3B82F7] hover:text-white hover:shadow-sm",
        expanded ? "justify-start gap-5" : "justify-center"
      )}
    >
      <span className="flex-shrink-0 w-5 h-5 [&_svg]:w-full [&_svg]:h-full [&_svg]:fill-current">
        {icon}
      </span>
      <span
        className={cn(
          "font-medium text-base whitespace-nowrap transition-all duration-700 ease-in-out overflow-hidden",
          expanded ? "opacity-100 w-auto" : "opacity-0 w-0"
        )}
      >
        {label}
      </span>
    </button>
  );
}
